    {q:"He was ___ to join the debate team because he feared public speaking.", choices:["ambitious","confident","reluctant","grateful"], answer:2, expl:"Reluctant means unwilling or hesitant to do something."},
    {q:"The instructions were ___, so nobody knew what to do.", choices:["vivid","precise","reluctant","ambiguous"], answer:3, expl:"Ambiguous means unclear, having more than one possible meaning."},
    {q:"She gave a ___ argument that convinced the entire class.", choices:["fragile","compelling","reluctant","trivial"], answer:1, expl:"Compelling means very convincing and powerful."},
    {q:"The scientist needed more ___ before drawing a conclusion.", choices:["evidence","absence","permission","curriculum"], answer:0, expl:"Evidence is facts or information that support or prove something."},
    {q:"His excuse sounded ___, so the teacher didn't believe him.", choices:["credible","inevitable","implausible","preliminary"], answer:2, expl:"Implausible means not believable or hard to accept as true."}
